import{_ as a,c as e,o as t,O as s}from"./chunks/framework.97fbe135.js";const g=JSON.parse('{"title":"如何安装模组？","description":"","frontmatter":{},"headers":[],"relativePath":"guide/install-mod.md","lastUpdated":1682417179000}'),r={name:"guide/install-mod.md"},i=s('<h1 id="如何安装模组" tabindex="-1">如何安装模组？ <a class="header-anchor" href="#如何安装模组" aria-label="Permalink to &quot;如何安装模组？&quot;">​</a></h1><p>因为今年2月份的时候手机版星露谷更新到了1.5.6版本，以往的smapi安装方法已经失效。所幸的是带佬更新了一个整合smapi补丁的游戏包，虽然还有很多bug以及不支持许多mod，但是至少还是可以尝鲜一下的。</p><h2 id="整合了smapi的星露谷" tabindex="-1">整合了smapi的星露谷 <a class="header-anchor" href="#整合了smapi的星露谷" aria-label="Permalink to &quot;整合了smapi的星露谷&quot;">​</a></h2><p>因为安卓smapi的作者迟迟未更新，有人便根据测试版的smapi做了一个整合包，下面是安装方法。</p><ol><li><p>下载带佬的整合包：<a href="https://drive.sysy.su/d/%E6%B8%B8%E6%88%8F/%E6%98%9F%E9%9C%B2%E8%B0%B7%E7%89%A9%E8%AF%AD/base_signed.apk?sign=hec9mplt6twHYdGVhPcxH7DSjLCApmFj-QHkPhhxg8M=:0" target="_blank" rel="noreferrer">base_signed.apk</a>，下载数据包：<a href="https://drive.sysy.su/d/%E6%B8%B8%E6%88%8F/%E6%98%9F%E9%9C%B2%E8%B0%B7%E7%89%A9%E8%AF%AD/com.zane.stardewvalley.zip?sign=_Q-U7YiNpPNQe2m-4ak2rkYUocwRNkowmeWVWpv9cQI=:0" target="_blank" rel="noreferrer">com.zane.stardewvalley.zip</a>。</p></li><li><p>安装整合包到手机上后<strong>先打开一下游戏</strong>，让其生成游戏数据文件夹。首次打开会报错，点击OK退出游戏。</p></li><li><p>打开MT管理器，在左边一栏找到刚才下载的数据包，单击它，在右边一栏找到游戏数据存放目录，一般在“/sdcard/Android/data”下，这时候你应该会看到一个名为“com.zane.stardewvalley”的文件夹。</p></li><li><p><strong>长按左边</strong>的“com.zane.stardewvalley”，在弹出的窗口点击<strong>解压</strong>，点击确定，这时候我们下载的数据包就替换掉了整合包里的数据。</p></li><li><p>然后返回桌面，点击桌面上的“SMAPI Stardew Valley”即可正常打开模组版本的星露谷啦！</p></li></ol>',5),o=[i];function l(n,p,d,c,_,m){return t(),e("div",null,o)}const E=a(r,[["render",l]]);export{g as __pageData,E as default};
